  9→/* PID parameters */
 10→float target_distance = 15.0f;
 11→float Kp = 50.0f;
 12→float Ki =  5.0f;
 13→float Kd = 10.0f;
 14→
 15→static PID_t pid;
 16→
 17→/* Simple float parser: "15", "15.5", "7.30" */
 18→static float parse_float(const char *s)
 19→{
 20→    float result = 0.0f;
 21→    float sign = 1.0f;
 22→    if (*s == '-') { sign = -1.0f; s++; }
 23→
 24→    while (*s >= '0' && *s <= '9') {
 25→        result = result * 10.0f + (*s - '0');
 26→        s++;
 27→    }
 28→    if (*s == '.') {
 29→        s++;
 30→        float frac = 0.1f;
 31→        while (*s >= '0' && *s <= '9') {
 32→            result += (*s - '0') * frac;
 33→            frac *= 0.1f;
 34→            s++;
 35→        }
 36→    }
 37→    return result * sign;
 38→}
