 40→int main(void)
 41→{
 42→    HAL_Init();
 43→    SystemClock_Config();
 44→
 45→    UART_Init();
 46→    Motor_Init();
 47→    HCSR04_Init();
 48→
 49→    pid.Kp = Kp;
 50→    pid.Ki = Ki;
 51→    pid.Kd = Kd;
 52→    pid.setpoint   = target_distance;
 53→    pid.output_min = -999.0f;
 54→    pid.output_max =  999.0f;
 55→    pid.dt         =  0.05f;
 56→    PID_Reset(&pid);
 57→
 58→    UART_Printf("PID started Kp=%d Ki=%d Kd=%d set=%d cm\r\n",
 59→                 (int)Kp, (int)Ki, (int)Kd, (int)target_distance);
 60→    UART_Printf("Send distance in cm (e.g. 20) to change target\r\n");
 61→
 62→    while (1)
 63→    {
 64→        /* Check for UART command */
 65→        char cmd[32];
 66→        if (UART_GetLine(cmd, sizeof(cmd)) > 0) {
 67→            float val = parse_float(cmd);
 68→            if (val > 0.0f && val <= 38.0f) {
 69→                target_distance = val;
 70→                pid.setpoint = target_distance;
 71→                PID_Reset(&pid);
 72→
 73→                int v_i = (int)val;
 74→                int v_f = (int)((val - (float)v_i) * 10.0f + 0.5f);
 75→                if (v_f >= 10) { v_i++; v_f = 0; }
 76→                UART_Printf(">>> SET target=%d.%d cm\r\n", v_i, v_f);
 77→            } else {
 78→                UART_Printf(">>> ERR: range 0.1-38.0 cm\r\n");
 79→            }
 80→        }
 81→
 82→        float distance = HCSR04_ReadDistance();
 83→
 84→        if (distance < 0.0f) {
 85→            Motor_Stop();
 86→            UART_Printf("t=%lu dist=ERR\r\n", HAL_GetTick());
 87→        } else {
 88→            float output = PID_Compute(&pid, distance);
 89→            Motor_SetSpeed((int16_t)output);
 90→
 91→            int d_i = (int)distance;
 92→            int d_f = (int)((distance - (float)d_i) * 10.0f + 0.5f);
 93→            if (d_f >= 10) { d_i++; d_f = 0; }
 94→
 95→            int s_i = (int)pid.setpoint;
 96→            int s_f = (int)((pid.setpoint - (float)s_i) * 10.0f + 0.5f);
 97→            if (s_f >= 10) { s_i++; s_f = 0; }
 98→
 99→            UART_Printf("t=%lu dist=%d.%d set=%d.%d out=%d\r\n",
100→                         HAL_GetTick(),
101→                         d_i, d_f,
102→                         s_i, s_f,
103→                         (int)output);
104→        }
105→
106→        HAL_Delay(50);
107→    }
108→}
