 1→#include "motor.h"
 2→#include "main.h"
 3→
 4→#define PWM_MAX  999
 5→
 6→void Motor_Init(void)
 7→{
 8→    /* Enable clocks: TIM4 (APB1), GPIOB (APB2) */
 9→    RCC->APB1ENR |= RCC_APB1ENR_TIM4EN;
10→    RCC->APB2ENR |= RCC_APB2ENR_IOPBEN;
11→
12→    /* PB6 = TIM4_CH1: AF push-pull, 50 MHz */
13→    GPIOB->CRL = (GPIOB->CRL & ~(0xFU << 24)) | (0xBU << 24);
14→    /* PB7 = TIM4_CH2: AF push-pull, 50 MHz */
15→    GPIOB->CRL = (GPIOB->CRL & ~(0xFU << 28)) | (0xBU << 28);
16→
17→    /* TIM4: PWM mode 1, CH1 + CH2, ARR = 999 -> 8 kHz @ 8 MHz */
18→    TIM4->PSC  = 0;
19→    TIM4->ARR  = PWM_MAX;
20→    TIM4->CCR1 = 0;
21→    TIM4->CCR2 = 0;
22→
23→    /* CH1: PWM mode 1 (110), preload enable */
24→    /* CH2: PWM mode 1 (110), preload enable */
25→    TIM4->CCMR1 = (6U << 4) | TIM_CCMR1_OC1PE
26→                | (6U << 12) | TIM_CCMR1_OC2PE;
27→
28→    /* Enable CH1 and CH2 outputs */
29→    TIM4->CCER = TIM_CCER_CC1E | TIM_CCER_CC2E;
30→
31→    /* ARR preload, start counter */
32→    TIM4->CR1 = TIM_CR1_ARPE | TIM_CR1_CEN;
33→}
34→
35→void Motor_SetSpeed(int16_t speed)
36→{
37→    if (speed >  PWM_MAX) speed =  PWM_MAX;
38→    if (speed < -PWM_MAX) speed = -PWM_MAX;
39→
40→    if (speed > 0) {
41→        TIM4->CCR1 = (uint16_t)speed;   /* forward */
42→        TIM4->CCR2 = 0;
43→    } else if (speed < 0) {
44→        TIM4->CCR1 = 0;
45→        TIM4->CCR2 = (uint16_t)(-speed); /* reverse */
46→    } else {
47→        TIM4->CCR1 = 0;
48→        TIM4->CCR2 = 0;
49→    }
50→}
51→
52→void Motor_Stop(void)
53→{
54→    TIM4->CCR1 = 0;
55→    TIM4->CCR2 = 0;
56→}
