 1→#include "hcsr04.h"
 2→#include "main.h"
 3→
 4→/* PB11 = Trig (output),  PB10 = Echo (input) */
 5→#define TRIG_PIN    (1U << 11)
 6→#define ECHO_PIN    (1U << 10)
 7→#define TIMEOUT_US  30000U
 8→
 9→void HCSR04_Init(void)
10→{
11→    /* Enable clocks: TIM3 (APB1), GPIOB (APB2) */
12→    RCC->APB1ENR |= RCC_APB1ENR_TIM3EN;
13→    RCC->APB2ENR |= RCC_APB2ENR_IOPBEN;
14→
15→    /* PB11 = Trig: GP push-pull output, 50 MHz  (CNF=00, MODE=11) */
16→    GPIOB->CRH = (GPIOB->CRH & ~(0xFU << 12)) | (0x3U << 12);
17→    /* PB10 = Echo: Floating input                (CNF=01, MODE=00) */
18→    GPIOB->CRH = (GPIOB->CRH & ~(0xFU << 8))  | (0x4U << 8);
19→
20→    GPIOB->BRR = TRIG_PIN;          /* Trig LOW */
21→
22→    /* TIM3: free-running 1 us counter (8 MHz / 8 = 1 MHz) */
23→    TIM3->PSC = 7;
24→    TIM3->ARR = 0xFFFF;
25→    TIM3->EGR = TIM_EGR_UG;         /* Force load PSC into shadow register */
26→    TIM3->SR  = 0;                   /* Clear update flag */
27→    TIM3->CR1 = TIM_CR1_CEN;
28→}
29→
30→float HCSR04_ReadDistance(void)
31→{
32→    /* 10 us trigger pulse */
33→    GPIOB->BSRR = TRIG_PIN;
34→    TIM3->CNT = 0;
35→    while (TIM3->CNT < 10) {}
36→    GPIOB->BRR = TRIG_PIN;
37→
38→    /* Wait for Echo rising edge */
39→    TIM3->CNT = 0;
40→    while (!(GPIOB->IDR & ECHO_PIN)) {
41→        if (TIM3->CNT > TIMEOUT_US) return -1.0f;
42→    }
43→
44→    /* Measure Echo HIGH duration */
45→    TIM3->CNT = 0;
46→    while (GPIOB->IDR & ECHO_PIN) {
47→        if (TIM3->CNT > TIMEOUT_US) return -1.0f;
48→    }
49→    uint16_t pulse_us = TIM3->CNT;
50→
51→    /* distance (cm) = pulse_us * 0.034 / 2 = pulse_us * 0.017 */
52→    return (float)pulse_us * 0.017f;
53→}
