  1→#include "uart_debug.h"
  2→#include "main.h"
  3→#include <stdio.h>
  4→#include <stdarg.h>
  5→
  6→static char tx_buf[128];
  7→
  8→/* Line assembly buffer */
  9→static char rx_line[32];
 10→static int  rx_pos = 0;
 11→
 12→/* ISR ring buffer */
 13→#define RX_RING_SIZE 64
 14→static volatile char rx_ring[RX_RING_SIZE];
 15→static volatile int  rx_head = 0;
 16→static volatile int  rx_tail = 0;
 17→
 18→void UART_Init(void)
 19→{
 20→    /* Enable clocks: USART1 (APB2), GPIOA (APB2) */
 21→    RCC->APB2ENR |= RCC_APB2ENR_USART1EN | RCC_APB2ENR_IOPAEN;
 22→
 23→    /* PA9  = USART1_TX : AF push-pull, 50 MHz */
 24→    GPIOA->CRH = (GPIOA->CRH & ~(0xFU << 4)) | (0xBU << 4);
 25→    /* PA10 = USART1_RX : Input pull-up */
 26→    GPIOA->CRH = (GPIOA->CRH & ~(0xFU << 8)) | (0x8U << 8);
 27→    GPIOA->ODR |= (1U << 10);   /* pull-up */
 28→
 29→    /* 115200 baud @ 8 MHz */
 30→    USART1->BRR = 0x0045;
 31→    /* TX + RX + RXNE interrupt + enable */
 32→    USART1->CR1 = USART_CR1_TE | USART_CR1_RE
 33→                | USART_CR1_RXNEIE | USART_CR1_UE;
 34→
 35→    NVIC_SetPriority(USART1_IRQn, 5);
 36→    NVIC_EnableIRQ(USART1_IRQn);
 37→}
 38→
 39→void UART_Printf(const char *fmt, ...)
 40→{
 41→    va_list args;
 42→    va_start(args, fmt);
 43→    int len = vsnprintf(tx_buf, sizeof(tx_buf), fmt, args);
 44→    va_end(args);
 45→
 46→    if (len > 0) {
 47→        if (len >= (int)sizeof(tx_buf))
 48→            len = (int)sizeof(tx_buf) - 1;
 49→        for (int i = 0; i < len; i++) {
 50→            while (!(USART1->SR & USART_SR_TXE)) {}
 51→            USART1->DR = (uint8_t)tx_buf[i];
 52→        }
 53→    }
 54→}
 55→
 56→void UART_SendStr(const char *s)
 57→{
 58→    while (*s) {
 59→        while (!(USART1->SR & USART_SR_TXE)) {}
 60→        USART1->DR = (uint8_t)*s++;
 61→    }
 62→}
 63→
 64→/* Called from USART1_IRQHandler — stores bytes in ring buffer */
 65→void UART_RxISR(void)
 66→{
 67→    while (USART1->SR & USART_SR_RXNE) {
 68→        char c = (char)(USART1->DR & 0xFF);
 69→        int next = (rx_head + 1) % RX_RING_SIZE;
 70→        if (next != rx_tail) {          /* not full */
 71→            rx_ring[rx_head] = c;
 72→            rx_head = next;
 73→        }
 74→    }
 75→    /* Clear ORE if set (read SR then DR — already done above) */
 76→    if (USART1->SR & USART_SR_ORE) {
 77→        (void)USART1->DR;
 78→    }
 79→}
 80→
 81→/**
 82→ * Non-blocking: drains ring buffer, assembles line.
 83→ * Returns line length when CR/LF received, 0 otherwise.
 84→ */
 85→int UART_GetLine(char *buf, int maxlen)
 86→{
 87→    while (rx_tail != rx_head) {
 88→        char c = rx_ring[rx_tail];
 89→        rx_tail = (rx_tail + 1) % RX_RING_SIZE;
 90→
 91→        if (c == '\r' || c == '\n') {
 92→            if (rx_pos > 0) {
 93→                int len = rx_pos;
 94→                if (len >= maxlen) len = maxlen - 1;
 95→                for (int i = 0; i < len; i++) buf[i] = rx_line[i];
 96→                buf[len] = '\0';
 97→                rx_pos = 0;
 98→                return len;
 99→            }
100→        } else {
101→            if (rx_pos < (int)sizeof(rx_line) - 1)
102→                rx_line[rx_pos++] = c;
103→        }
104→    }
105→    return 0;
106→}
107→
108→/* USART1 interrupt handler (weak in startup, we override) */
109→void USART1_IRQHandler(void)
110→{
111→    UART_RxISR();
112→}
