#include <stdio.h>
#include <string.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_log.h"
#include "esp_camera.h"
#include "quirc.h"

static const char *TAG = "QR_SCAN";

/* AI-Thinker ESP32-CAM pinout */
#define CAM_PIN_PWDN    32
#define CAM_PIN_RESET   (-1)
#define CAM_PIN_XCLK    0
#define CAM_PIN_SIOD    26
#define CAM_PIN_SIOC    27
#define CAM_PIN_D7      35
#define CAM_PIN_D6      34
#define CAM_PIN_D5      39
#define CAM_PIN_D4      36
#define CAM_PIN_D3      21
#define CAM_PIN_D2      19
#define CAM_PIN_D1      18
#define CAM_PIN_D0      5
#define CAM_PIN_VSYNC   25
#define CAM_PIN_HREF    23
#define CAM_PIN_PCLK    22
#define CAM_FLASH_PIN   4

static esp_err_t camera_init(void)
{
    camera_config_t config = {
        .pin_pwdn       = CAM_PIN_PWDN,
        .pin_reset      = CAM_PIN_RESET,
        .pin_xclk       = CAM_PIN_XCLK,
        .pin_sccb_sda   = CAM_PIN_SIOD,
        .pin_sccb_scl   = CAM_PIN_SIOC,
        .pin_d7         = CAM_PIN_D7,
        .pin_d6         = CAM_PIN_D6,
        .pin_d5         = CAM_PIN_D5,
        .pin_d4         = CAM_PIN_D4,
        .pin_d3         = CAM_PIN_D3,
        .pin_d2         = CAM_PIN_D2,
        .pin_d1         = CAM_PIN_D1,
        .pin_d0         = CAM_PIN_D0,
        .pin_vsync      = CAM_PIN_VSYNC,
        .pin_href       = CAM_PIN_HREF,
        .pin_pclk       = CAM_PIN_PCLK,

        .xclk_freq_hz   = 20000000,
        .ledc_timer     = LEDC_TIMER_0,
        .ledc_channel   = LEDC_CHANNEL_0,
        .pixel_format   = PIXFORMAT_GRAYSCALE,
        .frame_size     = FRAMESIZE_QVGA,       /* 320x240 */
        .jpeg_quality   = 12,
        .fb_count       = 1,
        .fb_location    = CAMERA_FB_IN_PSRAM,
        .grab_mode      = CAMERA_GRAB_WHEN_EMPTY,
    };

    esp_err_t err = esp_camera_init(&config);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Camera init failed: 0x%x", err);
    }
    return err;
}

static void qr_scan_task(void *arg)
{
    struct quirc *qr = quirc_new();
    if (!qr) {
        ESP_LOGE(TAG, "quirc_new() failed");
        vTaskDelete(NULL);
        return;
    }

    if (quirc_resize(qr, 320, 240) < 0) {
        ESP_LOGE(TAG, "quirc_resize() failed");
        quirc_destroy(qr);
        vTaskDelete(NULL);
        return;
    }

    ESP_LOGI(TAG, "Scanner ready. Point camera at a QR code...");

    while (1) {
        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) {
            ESP_LOGW(TAG, "Capture failed");
            vTaskDelay(pdMS_TO_TICKS(200));
            continue;
        }

        /* Feed frame to quirc */
        int w, h;
        uint8_t *buf = quirc_begin(qr, &w, &h);
        int copy_len = (fb->len < (size_t)(w * h)) ? fb->len : (w * h);
        memcpy(buf, fb->buf, copy_len);
        quirc_end(qr);

        esp_camera_fb_return(fb);

        /* Decode all found QR codes */
        int count = quirc_count(qr);
        for (int i = 0; i < count; i++) {
            struct quirc_code code;
            struct quirc_data data;

            quirc_extract(qr, i, &code);
            quirc_decode_error_t err = quirc_decode(&code, &data);

            if (err == QUIRC_SUCCESS) {
                ESP_LOGI(TAG, "========== QR CODE ==========");
                ESP_LOGI(TAG, "Data: %s", (char *)data.payload);
                ESP_LOGI(TAG, "Size: %d bytes", data.payload_len);
                ESP_LOGI(TAG, "Version: %d, ECC: %c",
                         data.version,
                         "MLHQ"[data.ecc_level]);
                ESP_LOGI(TAG, "=============================");
                /* Pause after successful read to avoid spam */
                vTaskDelay(pdMS_TO_TICKS(2000));
            }
        }

        vTaskDelay(pdMS_TO_TICKS(100));   /* ~10 fps */
    }
}

void app_main(void)
{
    ESP_LOGI(TAG, "=== ESP32-CAM QR Code Scanner ===");

    if (camera_init() != ESP_OK) {
        ESP_LOGE(TAG, "Camera init failed, restarting in 3 s...");
        vTaskDelay(pdMS_TO_TICKS(3000));
        esp_restart();
    }

    ESP_LOGI(TAG, "Camera OK");

    xTaskCreatePinnedToCore(
        qr_scan_task,   /* function   */
        "qr_scan",      /* name       */
        40 * 1024,      /* stack      */
        NULL,           /* arg        */
        5,              /* priority   */
        NULL,           /* handle     */
        0               /* core       */
    );
}

