#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "freertos/semphr.h"
#include "esp_log.h"
#include "esp_wifi.h"
#include "esp_event.h"
#include "esp_netif.h"
#include "esp_http_server.h"
#include "esp_camera.h"
#include "img_converters.h"
#include "nvs_flash.h"
#include "quirc.h"

static const char *TAG = "QR_SCAN";

/* ─── WiFi AP ─────────────────────────────────────────────── */
#define AP_SSID     "ESP32-QR-Scanner"
#define AP_PASS     "12345678"

/* ─── Camera pins (AI-Thinker ESP32-CAM) ──────────────────── */
#define CAM_PWDN   32
#define CAM_RESET  (-1)
#define CAM_XCLK   0
#define CAM_SIOD   26
#define CAM_SIOC   27
#define CAM_D7     35
#define CAM_D6     34
#define CAM_D5     39
#define CAM_D4     36
#define CAM_D3     21
#define CAM_D2     19
#define CAM_D1     18
#define CAM_D0     5
#define CAM_VSYNC  25
#define CAM_HREF   23
#define CAM_PCLK   22

#define FRAME_W    320
#define FRAME_H    240

/* ─── Shared state ────────────────────────────────────────── */
static SemaphoreHandle_t s_lock;
static uint8_t *s_jpg      = NULL;
static size_t   s_jpg_len  = 0;
static char     s_qr_text[1024] = "";
static bool     s_qr_found = false;

/* ─── Drawing ─────────────────────────────────────────────── */
static void draw_line(uint8_t *img, int W, int H,
                      int x0, int y0, int x1, int y1, uint8_t c)
{
    int dx =  abs(x1 - x0), sx = x0 < x1 ? 1 : -1;
    int dy = -abs(y1 - y0), sy = y0 < y1 ? 1 : -1;
    int err = dx + dy;
    for (;;) {
        for (int oy = -1; oy <= 1; oy++)
            for (int ox = -1; ox <= 1; ox++) {
                int px = x0 + ox, py = y0 + oy;
                if (px >= 0 && px < W && py >= 0 && py < H)
                    img[py * W + px] = c;
            }
        if (x0 == x1 && y0 == y1) break;
        int e2 = 2 * err;
        if (e2 >= dy) { err += dy; x0 += sx; }
        if (e2 <= dx) { err += dx; y0 += sy; }
    }
}

static void draw_quad(uint8_t *img, int W, int H,
                      struct quirc_point *corners, uint8_t c)
{
    for (int i = 0; i < 4; i++)
        draw_line(img, W, H,
                  corners[i].x, corners[i].y,
                  corners[(i + 1) % 4].x, corners[(i + 1) % 4].y, c);
}

/* ─── Camera init ─────────────────────────────────────────── */
static esp_err_t camera_init(void)
{
    camera_config_t cfg = {
        .pin_pwdn     = CAM_PWDN,   .pin_reset   = CAM_RESET,
        .pin_xclk     = CAM_XCLK,
        .pin_sccb_sda = CAM_SIOD,   .pin_sccb_scl = CAM_SIOC,
        .pin_d7 = CAM_D7, .pin_d6 = CAM_D6, .pin_d5 = CAM_D5, .pin_d4 = CAM_D4,
        .pin_d3 = CAM_D3, .pin_d2 = CAM_D2, .pin_d1 = CAM_D1, .pin_d0 = CAM_D0,
        .pin_vsync    = CAM_VSYNC,
        .pin_href     = CAM_HREF,
        .pin_pclk     = CAM_PCLK,
        .xclk_freq_hz = 20000000,
        .ledc_timer   = LEDC_TIMER_0,
        .ledc_channel = LEDC_CHANNEL_0,
        .pixel_format = PIXFORMAT_GRAYSCALE,
        .frame_size   = FRAMESIZE_QVGA,
        .jpeg_quality = 12,
        .fb_count     = 1,
        .fb_location  = CAMERA_FB_IN_PSRAM,
        .grab_mode    = CAMERA_GRAB_WHEN_EMPTY,
    };
    esp_err_t err = esp_camera_init(&cfg);
    if (err != ESP_OK) ESP_LOGE(TAG, "Camera init failed: 0x%x", err);
    return err;
}

/* ─── WiFi AP ─────────────────────────────────────────────── */
static void wifi_init_ap(void)
{
    ESP_ERROR_CHECK(esp_netif_init());
    ESP_ERROR_CHECK(esp_event_loop_create_default());
    esp_netif_create_default_wifi_ap();

    wifi_init_config_t wcfg = WIFI_INIT_CONFIG_DEFAULT();
    ESP_ERROR_CHECK(esp_wifi_init(&wcfg));

    wifi_config_t ap = {
        .ap = {
            .ssid           = AP_SSID,
            .password       = AP_PASS,
            .ssid_len       = sizeof(AP_SSID) - 1,
            .channel        = 1,
            .max_connection = 3,
            .authmode       = WIFI_AUTH_WPA2_PSK,
        },
    };
    ESP_ERROR_CHECK(esp_wifi_set_mode(WIFI_MODE_AP));
    ESP_ERROR_CHECK(esp_wifi_set_config(WIFI_IF_AP, &ap));
    ESP_ERROR_CHECK(esp_wifi_start());

    ESP_LOGI(TAG, "WiFi AP: SSID=\"%s\" PASS=\"%s\"", AP_SSID, AP_PASS);
    ESP_LOGI(TAG, "Open http://192.168.4.1");
}

/* ─── QR scan task ────────────────────────────────────────── */
static void qr_task(void *arg)
{
    struct quirc *qr = quirc_new();
    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
        ESP_LOGE(TAG, "quirc init failed");
        vTaskDelete(NULL);
        return;
    }
    ESP_LOGI(TAG, "QR scanner ready");

    while (1) {
        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) { vTaskDelay(pdMS_TO_TICKS(200)); continue; }

        /* decode */
        int w, h;
        uint8_t *qbuf = quirc_begin(qr, &w, &h);
        memcpy(qbuf, fb->buf, w * h);
        quirc_end(qr);

        bool found = false;
        int n = quirc_count(qr);
        for (int i = 0; i < n; i++) {
            struct quirc_code code;
            struct quirc_data data;
            quirc_extract(qr, i, &code);
            if (quirc_decode(&code, &data) == QUIRC_SUCCESS) {
                draw_quad(fb->buf, FRAME_W, FRAME_H, code.corners, 255);

                xSemaphoreTake(s_lock, portMAX_DELAY);
                strncpy(s_qr_text, (char *)data.payload, sizeof(s_qr_text) - 1);
                s_qr_text[sizeof(s_qr_text) - 1] = '\0';
                s_qr_found = true;
                xSemaphoreGive(s_lock);

                found = true;
                ESP_LOGI(TAG, "QR: %s", (char *)data.payload);
            }
        }
        if (!found) {
            xSemaphoreTake(s_lock, portMAX_DELAY);
            s_qr_found = false;
            xSemaphoreGive(s_lock);
        }

        /* grayscale -> JPEG */
        uint8_t *jpg = NULL;
        size_t jlen = 0;
        bool ok = fmt2jpg(fb->buf, fb->len, fb->width, fb->height,
                          PIXFORMAT_GRAYSCALE, 80, &jpg, &jlen);
        esp_camera_fb_return(fb);

        if (ok && jpg) {
            xSemaphoreTake(s_lock, portMAX_DELAY);
            free(s_jpg);
            s_jpg     = jpg;
            s_jpg_len = jlen;
            xSemaphoreGive(s_lock);
        } else {
            free(jpg);
        }

        vTaskDelay(pdMS_TO_TICKS(80));
    }
}

/* ─── HTTP: index page ────────────────────────────────────── */
static const char INDEX_HTML[] =
"<!DOCTYPE html><html><head>"
"<meta charset=\"utf-8\">"
"<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">"
"<title>ESP32 QR Scanner</title>"
"<style>"
"*{margin:0;padding:0;box-sizing:border-box}"
"body{background:#0f0f1a;color:#e0e0e0;font-family:'Courier New',monospace;"
"display:flex;flex-direction:column;align-items:center;padding:20px}"
"h1{color:#e94560;margin-bottom:16px;font-size:1.5em}"
"#cam{border:2px solid #e94560;border-radius:8px;width:640px;height:480px;"
"object-fit:contain;background:#000}"
"#qr{background:#16213e;padding:14px 20px;margin-top:14px;border-radius:8px;"
"width:640px;min-height:48px;font-size:1.1em;word-break:break-all}"
".found{color:#0f0}.no{color:#555}"
"</style></head><body>"
"<h1>ESP32-CAM QR Scanner</h1>"
"<img id=\"cam\"/>"
"<div id=\"qr\"><span class=\"no\">scanning...</span></div>"
"<script>"
"document.getElementById('cam').src='http://'+location.hostname+':81/stream';"
"setInterval(()=>{"
"fetch('/qr').then(r=>r.json()).then(d=>{"
"const e=document.getElementById('qr');"
"if(d.found)e.innerHTML='<span class=\"found\">'+d.data.replace(/&/g,'&amp;')"
".replace(/</g,'&lt;').replace(/>/g,'&gt;')+'</span>';"
"else e.innerHTML='<span class=\"no\">scanning...</span>';"
"}).catch(()=>{})},500);"
"</script></body></html>";

static esp_err_t index_handler(httpd_req_t *req)
{
    httpd_resp_set_type(req, "text/html");
    return httpd_resp_send(req, INDEX_HTML, sizeof(INDEX_HTML) - 1);
}

/* ─── HTTP: QR result JSON ────────────────────────────────── */
static esp_err_t qr_handler(httpd_req_t *req)
{
    char buf[1200];

    xSemaphoreTake(s_lock, portMAX_DELAY);
    if (s_qr_found) {
        /* minimal JSON-escape */
        char esc[1024];
        int j = 0;
        for (int i = 0; s_qr_text[i] && j < (int)sizeof(esc) - 6; i++) {
            char c = s_qr_text[i];
            if (c == '"' || c == '\\') esc[j++] = '\\';
            else if (c == '\n') { esc[j++] = '\\'; c = 'n'; }
            else if (c == '\r') { esc[j++] = '\\'; c = 'r'; }
            esc[j++] = c;
        }
        esc[j] = '\0';
        snprintf(buf, sizeof(buf), "{\"found\":true,\"data\":\"%s\"}", esc);
    } else {
        strcpy(buf, "{\"found\":false,\"data\":\"\"}");
    }
    xSemaphoreGive(s_lock);

    httpd_resp_set_type(req, "application/json");
    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
    return httpd_resp_send(req, buf, strlen(buf));
}

/* ─── HTTP: MJPEG stream ─────────────────────────────────── */
#define BOUNDARY "espframe"
static const char *STREAM_CT =
    "multipart/x-mixed-replace;boundary=" BOUNDARY;

static esp_err_t stream_handler(httpd_req_t *req)
{
    httpd_resp_set_type(req, STREAM_CT);
    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");

    char hdr[80];
    esp_err_t res = ESP_OK;

    while (res == ESP_OK) {
        xSemaphoreTake(s_lock, portMAX_DELAY);
        size_t len = s_jpg_len;
        uint8_t *copy = NULL;
