240→/* ─── HTTP: QR result JSON ────────────────────────────────── */
241→static esp_err_t qr_handler(httpd_req_t *req)
242→{
243→    char buf[1200];
244→
245→    xSemaphoreTake(s_lock, portMAX_DELAY);
246→    if (s_qr_found) {
247→        /* minimal JSON-escape */
248→        char esc[1024];
249→        int j = 0;
250→        for (int i = 0; s_qr_text[i] && j < (int)sizeof(esc) - 6; i++) {
251→            char c = s_qr_text[i];
252→            if (c == '"' || c == '\\') esc[j++] = '\\';
253→            else if (c == '\n') { esc[j++] = '\\'; c = 'n'; }
254→            else if (c == '\r') { esc[j++] = '\\'; c = 'r'; }
255→            esc[j++] = c;
256→        }
257→        esc[j] = '\0';
258→        snprintf(buf, sizeof(buf), "{\"found\":true,\"data\":\"%s\"}", esc);
259→    } else {
260→        strcpy(buf, "{\"found\":false,\"data\":\"\"}");
261→    }
262→    xSemaphoreGive(s_lock);
263→
264→    httpd_resp_set_type(req, "application/json");
265→    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
266→    return httpd_resp_send(req, buf, strlen(buf));
267→}
