269→/* ─── HTTP: MJPEG stream ─────────────────────────────────── */
270→#define BOUNDARY "espframe"
271→static const char *STREAM_CT =
272→    "multipart/x-mixed-replace;boundary=" BOUNDARY;
273→
274→static esp_err_t stream_handler(httpd_req_t *req)
275→{
276→    httpd_resp_set_type(req, STREAM_CT);
277→    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
278→
279→    char hdr[80];
280→    esp_err_t res = ESP_OK;
281→
282→    while (res == ESP_OK) {
283→        xSemaphoreTake(s_lock, portMAX_DELAY);
284→        size_t len = s_jpg_len;
285→        uint8_t *copy = NULL;
286→        if (len) {
287→            copy = (uint8_t *)malloc(len);
288→            if (copy) memcpy(copy, s_jpg, len);
289→        }
290→        xSemaphoreGive(s_lock);
291→
292→        if (!copy) { vTaskDelay(pdMS_TO_TICKS(100)); continue; }
293→
294→        int hlen = snprintf(hdr, sizeof(hdr),
295→            "--" BOUNDARY "\r\nContent-Type:image/jpeg\r\n"
296→            "Content-Length:%u\r\n\r\n", (unsigned)len);
297→
298→        res = httpd_resp_send_chunk(req, hdr, hlen);
299→        if (res == ESP_OK) res = httpd_resp_send_chunk(req, (char *)copy, len);
300→        if (res == ESP_OK) res = httpd_resp_send_chunk(req, "\r\n", 2);
301→
302→        free(copy);
303→        vTaskDelay(pdMS_TO_TICKS(80));
304→    }
305→    return res;
306→}
