308→/* ─── Start two HTTP servers ──────────────────────────────── */
309→static void start_webserver(void)
310→{
311→    /* port 80: page + API */
312→    httpd_config_t cfg80 = HTTPD_DEFAULT_CONFIG();
313→    cfg80.server_port = 80;
314→    cfg80.lru_purge_enable = true;
315→    httpd_handle_t h80 = NULL;
316→    ESP_ERROR_CHECK(httpd_start(&h80, &cfg80));
317→
318→    httpd_uri_t uri_idx = { .uri="/",   .method=HTTP_GET, .handler=index_handler };
319→    httpd_uri_t uri_qr  = { .uri="/qr", .method=HTTP_GET, .handler=qr_handler };
320→    httpd_register_uri_handler(h80, &uri_idx);
321→    httpd_register_uri_handler(h80, &uri_qr);
322→
323→    /* port 81: MJPEG stream (separate server so API stays responsive) */
324→    httpd_config_t cfg81 = HTTPD_DEFAULT_CONFIG();
325→    cfg81.server_port = 81;
326→    cfg81.ctrl_port   = 32769;
327→    cfg81.lru_purge_enable = true;
328→    httpd_handle_t h81 = NULL;
329→    ESP_ERROR_CHECK(httpd_start(&h81, &cfg81));
330→
331→    httpd_uri_t uri_stm = { .uri="/stream", .method=HTTP_GET, .handler=stream_handler };
332→    httpd_register_uri_handler(h81, &uri_stm);
333→}
