336→void app_main(void)
337→{
338→    ESP_LOGI(TAG, "=== ESP32-CAM QR Scanner ===");
339→
340→    /* NVS (required by WiFi) */
341→    esp_err_t ret = nvs_flash_init();
342→    if (ret == ESP_ERR_NVS_NO_FREE_PAGES ||
343→        ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
344→        ESP_ERROR_CHECK(nvs_flash_erase());
345→        ret = nvs_flash_init();
346→    }
347→    ESP_ERROR_CHECK(ret);
348→
349→    s_lock = xSemaphoreCreateMutex();
350→
351→    /* camera */
352→    if (camera_init() != ESP_OK) {
353→        ESP_LOGE(TAG, "Camera FAIL, restarting in 3 s...");
354→        vTaskDelay(pdMS_TO_TICKS(3000));
355→        esp_restart();
