        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    s_lock = xSemaphoreCreateMutex();

    /* camera */
    if (camera_init() != ESP_OK) {
        ESP_LOGE(TAG, "Camera FAIL, restarting in 3 s...");
        vTaskDelay(pdMS_TO_TICKS(3000));
        esp_restart();
    }
    ESP_LOGI(TAG, "Camera OK");

    /* WiFi AP */
    wifi_init_ap();

    /* web server */
    start_webserver();

    /* QR scan task on core 0 */
    xTaskCreatePinnedToCore(qr_task, "qr", 40 * 1024, NULL, 5, NULL, 0);
}

