108→/* ─── QR scan task ────────────────────────────────────────── */
109→static void qr_task(void *arg)
110→{
111→    struct quirc *qr = quirc_new();
112→    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
113→        ESP_LOGE(TAG, "quirc init failed");
114→        vTaskDelete(NULL);
115→        return;
116→    }
117→
118→    /* persistent buffers in PSRAM */
119→    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
120→    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
121→    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
122→    if (!rgb || !code || !data) {
123→        ESP_LOGE(TAG, "PSRAM alloc failed");
124→        vTaskDelete(NULL);
125→        return;
126→    }
127→
128→    ESP_LOGI(TAG, "QR scanner ready (PSRAM free: %lu)",
129→             (unsigned long)heap_caps_get_free_size(MALLOC_CAP_SPIRAM));
130→
131→    while (1) {
132→        camera_fb_t *fb = esp_camera_fb_get();
133→        if (!fb) { vTaskDelay(pdMS_TO_TICKS(200)); continue; }
134→
135→        /* ---- store JPEG for streaming (just copy, no conversion) ---- */
136→        uint8_t *jpg_copy = heap_caps_malloc(fb->len, MALLOC_CAP_SPIRAM);
137→        if (jpg_copy) {
138→            memcpy(jpg_copy, fb->buf, fb->len);
139→            xSemaphoreTake(s_lock, portMAX_DELAY);
140→            free(s_jpg);
141→            s_jpg     = jpg_copy;
142→            s_jpg_len = fb->len;
143→            xSemaphoreGive(s_lock);
144→        }
145→
146→        /* ---- decode JPEG → RGB888 → grayscale → quirc ---- */
147→        bool decoded = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
148→        esp_camera_fb_return(fb);
149→
150→        if (!decoded) {
151→            ESP_LOGW(TAG, "JPEG decode failed");
152→            vTaskDelay(pdMS_TO_TICKS(100));
153→            continue;
154→        }
155→
156→        /* RGB888 → grayscale (BT.601 luma) */
157→        int w, h;
158→        uint8_t *qbuf = quirc_begin(qr, &w, &h);
159→        int pixels = w * h;
160→        for (int i = 0; i < pixels; i++) {
161→            int ri = i * 3;
162→            qbuf[i] = (uint8_t)((rgb[ri] * 77 + rgb[ri+1] * 150 + rgb[ri+2] * 29) >> 8);
163→        }
164→        quirc_end(qr);
165→
166→        /* ---- decode QR codes ---- */
167→        bool found = false;
168→        int n = quirc_count(qr);
169→        for (int i = 0; i < n; i++) {
170→            quirc_extract(qr, i, code);
171→            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
172→                xSemaphoreTake(s_lock, portMAX_DELAY);
173→                int plen = data->payload_len;
174→                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
175→                memcpy(s_qr_text, data->payload, plen);
176→                s_qr_text[plen] = '\0';
177→                s_qr_found = true;
178→                for (int j = 0; j < 4; j++) {
179→                    s_qr_corners[j * 2]     = code->corners[j].x;
180→                    s_qr_corners[j * 2 + 1] = code->corners[j].y;
181→                }
182→                xSemaphoreGive(s_lock);
183→
184→                found = true;
185→                ESP_LOGI(TAG, "QR: %.128s", s_qr_text);
186→                break;
187→            }
188→        }
189→        if (!found) {
190→            xSemaphoreTake(s_lock, portMAX_DELAY);
191→            s_qr_found = false;
192→            xSemaphoreGive(s_lock);
193→        }
194→
195→        vTaskDelay(pdMS_TO_TICKS(100));
196→    }
197→}
