/* ─── WiFi AP ─────────────────────────────────────────────── */
static void wifi_init_ap(void)
{
    ESP_ERROR_CHECK(esp_netif_init());
    ESP_ERROR_CHECK(esp_event_loop_create_default());
    esp_netif_create_default_wifi_ap();

    wifi_init_config_t wcfg = WIFI_INIT_CONFIG_DEFAULT();
    ESP_ERROR_CHECK(esp_wifi_init(&wcfg));

    wifi_config_t ap = {
        .ap = {
            .ssid           = AP_SSID,
            .password       = AP_PASS,
            .ssid_len       = sizeof(AP_SSID) - 1,
            .channel        = 1,
            .max_connection = 3,
            .authmode       = WIFI_AUTH_WPA2_PSK,
        },
    };
    ESP_ERROR_CHECK(esp_wifi_set_mode(WIFI_MODE_AP));
    ESP_ERROR_CHECK(esp_wifi_set_config(WIFI_IF_AP, &ap));
    ESP_ERROR_CHECK(esp_wifi_start());

    ESP_LOGI(TAG, "WiFi AP: SSID=\"%s\" PASS=\"%s\"", AP_SSID, AP_PASS);
    ESP_LOGI(TAG, "Open http://192.168.4.1");
}

/* ─── QR scan task ────────────────────────────────────────── */
static void qr_task(void *arg)
{
    struct quirc *qr = quirc_new();
    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
        ESP_LOGE(TAG, "quirc init failed");
        vTaskDelete(NULL);
        return;
    }

    /* persistent buffers in PSRAM */
    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
    if (!rgb || !code || !data) {
        ESP_LOGE(TAG, "PSRAM alloc failed");
        vTaskDelete(NULL);
        return;
    }

    ESP_LOGI(TAG, "QR scanner ready (PSRAM free: %lu)",
             (unsigned long)heap_caps_get_free_size(MALLOC_CAP_SPIRAM));

    while (1) {
        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) { vTaskDelay(pdMS_TO_TICKS(200)); continue; }

        /* ---- store JPEG for streaming (just copy, no conversion) ---- */
        uint8_t *jpg_copy = heap_caps_malloc(fb->len, MALLOC_CAP_SPIRAM);
        if (jpg_copy) {
            memcpy(jpg_copy, fb->buf, fb->len);
            xSemaphoreTake(s_lock, portMAX_DELAY);
            free(s_jpg);
            s_jpg     = jpg_copy;
            s_jpg_len = fb->len;
            xSemaphoreGive(s_lock);
        }

        /* ---- decode JPEG → RGB888 → grayscale → quirc ---- */
        bool decoded = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
        esp_camera_fb_return(fb);

        if (!decoded) {
            ESP_LOGW(TAG, "JPEG decode failed");
            vTaskDelay(pdMS_TO_TICKS(100));
            continue;
        }

        /* RGB888 → grayscale (BT.601 luma) */
        int w, h;
        uint8_t *qbuf = quirc_begin(qr, &w, &h);
        int pixels = w * h;
        for (int i = 0; i < pixels; i++) {
            int ri = i * 3;
            qbuf[i] = (uint8_t)((rgb[ri] * 77 + rgb[ri+1] * 150 + rgb[ri+2] * 29) >> 8);
        }
        quirc_end(qr);

        /* ---- decode QR codes ---- */
        bool found = false;
        int n = quirc_count(qr);
        for (int i = 0; i < n; i++) {
            quirc_extract(qr, i, code);
            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
                xSemaphoreTake(s_lock, portMAX_DELAY);
                int plen = data->payload_len;
                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
                memcpy(s_qr_text, data->payload, plen);
                s_qr_text[plen] = '\0';
                s_qr_found = true;
                for (int j = 0; j < 4; j++) {
                    s_qr_corners[j * 2]     = code->corners[j].x;
                    s_qr_corners[j * 2 + 1] = code->corners[j].y;
                }
                xSemaphoreGive(s_lock);

                found = true;
                ESP_LOGI(TAG, "QR: %.128s", s_qr_text);
                break;
            }
        }
        if (!found) {
            xSemaphoreTake(s_lock, portMAX_DELAY);
            s_qr_found = false;
            xSemaphoreGive(s_lock);
        }

        vTaskDelay(pdMS_TO_TICKS(100));
    }
}

/* ─── HTTP: index page ────────────────────────────────────── */
static const char INDEX_HTML[] =
"<!DOCTYPE html><html><head>"
"<meta charset=\"utf-8\">"
"<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">"
"<title>ESP32 QR Scanner</title>"
