static esp_err_t index_handler(httpd_req_t *req)
{
    httpd_resp_set_type(req, "text/html");
    return httpd_resp_send(req, INDEX_HTML, sizeof(INDEX_HTML) - 1);
}

/* ─── HTTP: QR result JSON ────────────────────────────────── */
static esp_err_t qr_handler(httpd_req_t *req)
{
    char buf[1300];

    xSemaphoreTake(s_lock, portMAX_DELAY);
    if (s_qr_found) {
        char esc[1024];
        int j = 0;
        for (int i = 0; s_qr_text[i] && j < (int)sizeof(esc) - 6; i++) {
            char c = s_qr_text[i];
            if (c == '"' || c == '\\') esc[j++] = '\\';
            else if (c == '\n') { esc[j++] = '\\'; c = 'n'; }
            else if (c == '\r') { esc[j++] = '\\'; c = 'r'; }
            esc[j++] = c;
        }
        esc[j] = '\0';
        snprintf(buf, sizeof(buf),
                 "{\"found\":true,\"data\":\"%s\","
                 "\"c\":[%d,%d,%d,%d,%d,%d,%d,%d]}",
                 esc,
                 s_qr_corners[0], s_qr_corners[1],
                 s_qr_corners[2], s_qr_corners[3],
                 s_qr_corners[4], s_qr_corners[5],
                 s_qr_corners[6], s_qr_corners[7]);
    } else {
        strcpy(buf, "{\"found\":false,\"data\":\"\"}");
    }
    xSemaphoreGive(s_lock);

    httpd_resp_set_type(req, "application/json");
    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
    return httpd_resp_send(req, buf, strlen(buf));
}

/* ─── HTTP: MJPEG stream ─────────────────────────────────── */
#define BOUNDARY "espframe"
static const char *STREAM_CT =
    "multipart/x-mixed-replace;boundary=" BOUNDARY;

static esp_err_t stream_handler(httpd_req_t *req)
{
    httpd_resp_set_type(req, STREAM_CT);
    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");

    char hdr[100];
    esp_err_t res = ESP_OK;

    while (res == ESP_OK) {
        xSemaphoreTake(s_lock, portMAX_DELAY);
        size_t len = s_jpg_len;
        uint8_t *copy = NULL;
        if (len) {
            copy = (uint8_t *)malloc(len);
            if (copy) memcpy(copy, s_jpg, len);
        }
        xSemaphoreGive(s_lock);

        if (!copy) { vTaskDelay(pdMS_TO_TICKS(100)); continue; }

        int hlen = snprintf(hdr, sizeof(hdr),
            "--" BOUNDARY "\r\nContent-Type:image/jpeg\r\n"
            "Content-Length:%u\r\n\r\n", (unsigned)len);

        res = httpd_resp_send_chunk(req, hdr, hlen);
        if (res == ESP_OK) res = httpd_resp_send_chunk(req, (char *)copy, len);
        if (res == ESP_OK) res = httpd_resp_send_chunk(req, "\r\n", 2);

        free(copy);
        vTaskDelay(pdMS_TO_TICKS(80));
    }
    return res;
}

/* ─── Start two HTTP servers ──────────────────────────────── */
static void start_webserver(void)
{
    /* port 80: page + API */
    httpd_config_t cfg80 = HTTPD_DEFAULT_CONFIG();
    cfg80.server_port = 80;
    cfg80.lru_purge_enable = true;
    cfg80.stack_size = 8192;
    httpd_handle_t h80 = NULL;
    ESP_ERROR_CHECK(httpd_start(&h80, &cfg80));

    httpd_uri_t uri_idx = { .uri="/",   .method=HTTP_GET, .handler=index_handler };
    httpd_uri_t uri_qr  = { .uri="/qr", .method=HTTP_GET, .handler=qr_handler };
    httpd_register_uri_handler(h80, &uri_idx);
    httpd_register_uri_handler(h80, &uri_qr);

    /* port 81: MJPEG stream */
    httpd_config_t cfg81 = HTTPD_DEFAULT_CONFIG();
    cfg81.server_port = 81;
    cfg81.ctrl_port   = 32769;
    cfg81.lru_purge_enable = true;
    cfg81.stack_size = 8192;
    httpd_handle_t h81 = NULL;
    ESP_ERROR_CHECK(httpd_start(&h81, &cfg81));

    httpd_uri_t uri_stm = { .uri="/stream", .method=HTTP_GET, .handler=stream_handler };
    httpd_register_uri_handler(h81, &uri_stm);
}

/* ─── app_main ────────────────────────────────────────────── */
void app_main(void)
{
    ESP_LOGI(TAG, "=== ESP32-CAM QR Scanner ===");

    esp_err_t ret = nvs_flash_init();
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES ||
        ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    s_lock = xSemaphoreCreateMutex();

    if (camera_init() != ESP_OK) {
        ESP_LOGE(TAG, "Camera FAIL, restarting in 3 s...");
        vTaskDelay(pdMS_TO_TICKS(3000));
        esp_restart();
    }
    ESP_LOGI(TAG, "Camera OK");

    wifi_init_ap();
    start_webserver();

    xTaskCreatePinnedToCore(qr_task, "qr", 64 * 1024, NULL, 5, NULL, 0);
}

