324→static esp_err_t stream_handler(httpd_req_t *req)
325→{
326→    esp_err_t res;
327→    char hdr[80];
328→
329→    res = httpd_resp_set_type(req, "multipart/x-mixed-replace;boundary=" BOUNDARY);
330→    if (res != ESP_OK) return res;
331→
332→    ESP_LOGI(TAG, "Stream client connected");
333→
334→    while (true) {
335→        camera_fb_t *fb = esp_camera_fb_get();
336→        if (!fb) {
337→            ESP_LOGE(TAG, "stream: fb_get fail");
338→            vTaskDelay(pdMS_TO_TICKS(100));
339→            continue;
340→        }
341→
342→        int hlen = snprintf(hdr, sizeof(hdr),
343→            "--" BOUNDARY "\r\n"
344→            "Content-Type: image/jpeg\r\n"
345→            "Content-Length: %u\r\n\r\n", (unsigned)fb->len);
346→
347→        res = httpd_resp_send_chunk(req, hdr, hlen);
348→        if (res == ESP_OK)
349→            res = httpd_resp_send_chunk(req, (const char *)fb->buf, fb->len);
350→        if (res == ESP_OK)
351→            res = httpd_resp_send_chunk(req, "\r\n", 2);
352→
353→        esp_camera_fb_return(fb);
354→
355→        if (res != ESP_OK) {
356→            ESP_LOGI(TAG, "Stream client disconnected");
357→            break;
358→        }
359→        vTaskDelay(pdMS_TO_TICKS(30));
360→    }
361→    return res;
362→}
