167→static esp_err_t camera_probe(const camera_config_t *config, camera_model_t *out_camera_model)
168→{
169→    esp_err_t ret = ESP_OK;
170→    *out_camera_model = CAMERA_NONE;
171→    if (s_state != NULL) {
172→        return ESP_ERR_INVALID_STATE;
173→    }
174→
175→    s_state = (camera_state_t *) calloc(1, sizeof(camera_state_t));
176→    if (!s_state) {
177→        return ESP_ERR_NO_MEM;
178→    }
179→
180→    if (config->pin_xclk >= 0) {
181→        ESP_LOGD(TAG, "Enabling XCLK output");
182→        CAMERA_ENABLE_OUT_CLOCK(config);
183→    }
184→
185→    if (config->pin_sccb_sda != -1) {
186→        ESP_LOGD(TAG, "Initializing SCCB");
187→        ret = SCCB_Init(config->pin_sccb_sda, config->pin_sccb_scl);
188→    } else {
189→        ESP_LOGD(TAG, "Using existing I2C port");
190→        ret = SCCB_Use_Port(config->sccb_i2c_port);
191→    }
192→
193→    if(ret != ESP_OK) {
194→        ESP_LOGE(TAG, "sccb init err");
195→        goto err;
196→    }
197→
198→    if (config->pin_pwdn >= 0) {
199→        ESP_LOGD(TAG, "Resetting camera by power down line");
200→        gpio_config_t conf = { 0 };
201→        conf.pin_bit_mask = 1LL << config->pin_pwdn;
202→        conf.mode = GPIO_MODE_OUTPUT;
203→        gpio_config(&conf);
204→
205→        // careful, logic is inverted compared to reset pin
206→        gpio_set_level(config->pin_pwdn, 1);
207→        vTaskDelay(10 / portTICK_PERIOD_MS);
208→        gpio_set_level(config->pin_pwdn, 0);
209→        vTaskDelay(10 / portTICK_PERIOD_MS);
210→    }
211→
212→    if (config->pin_reset >= 0) {
213→        ESP_LOGD(TAG, "Resetting camera");
214→        gpio_config_t conf = { 0 };
215→        conf.pin_bit_mask = 1LL << config->pin_reset;
216→        conf.mode = GPIO_MODE_OUTPUT;
217→        gpio_config(&conf);
218→
219→        gpio_set_level(config->pin_reset, 0);
220→        vTaskDelay(10 / portTICK_PERIOD_MS);
221→        gpio_set_level(config->pin_reset, 1);
222→        vTaskDelay(10 / portTICK_PERIOD_MS);
223→    }
224→
225→    ESP_LOGD(TAG, "Searching for camera address");
226→    vTaskDelay(10 / portTICK_PERIOD_MS);
227→
228→    int camera_model_id;
229→    uint8_t slv_addr = 0x0;
230→
231→    /**
232→     * This loop probes each known sensor until a supported camera is detected
233→     */
234→    for(camera_model_id = 0; *out_camera_model == CAMERA_NONE && camera_model_id < CAMERA_MODEL_MAX ; camera_model_id++) {
235→        slv_addr = camera_sensor[camera_model_id].sccb_addr;
236→
237→        if (ESP_OK != SCCB_Probe(slv_addr)) {
238→            continue;
239→        }
240→
241→        s_state->sensor.slv_addr = slv_addr;
242→        s_state->sensor.xclk_freq_hz = config->xclk_freq_hz;
243→
244→        /**
245→         * Read sensor ID and then initialize sensor
246→         * Attention: Some sensors have the same SCCB address. Therefore, several attempts may be made in the detection process
247→         */
248→        sensor_id_t *id = &s_state->sensor.id;
249→
250→        for (size_t i = 0; i < sizeof(g_sensors) / sizeof(sensor_func_t); i++) {
251→            if (g_sensors[i].detect(slv_addr, id)) {
252→                ESP_LOGI(TAG, "Camera PID=0x%02x VER=0x%02x MIDL=0x%02x MIDH=0x%02x",
253→                    id->PID, id->VER, id->MIDH, id->MIDL);
254→                camera_sensor_info_t *info = esp_camera_sensor_get_info(id);
255→                if (NULL != info) {
256→                    *out_camera_model = info->model;
257→                    ESP_LOGI(TAG, "Detected %s camera", info->name);
258→                    g_sensors[i].init(&s_state->sensor);
259→                    break;
260→                }
261→            }
262→        }
263→    }
264→
265→    if (CAMERA_NONE == *out_camera_model) { //If no supported sensors are detected
266→        ESP_LOGE(TAG, "Detected camera not supported.");
267→        ret = ESP_ERR_NOT_SUPPORTED;
268→        goto err;
269→    }
270→
271→    ESP_LOGI(TAG, "Detected camera at address=0x%02x", slv_addr);
272→
273→    ESP_LOGD(TAG, "Doing SW reset of sensor");
274→    vTaskDelay(10 / portTICK_PERIOD_MS);
275→
276→    return s_state->sensor.reset(&s_state->sensor);
277→err :
278→    CAMERA_DISABLE_OUT_CLOCK();
279→    return ret;
280→}
