299→esp_err_t esp_camera_init(const camera_config_t *config)
300→{
301→    esp_err_t err;
302→    s_saved_config = *config;
303→    err = cam_init(config);
304→    if (err != ESP_OK) {
305→        ESP_LOGE(TAG, "Camera init failed with error 0x%x", err);
306→        return err;
307→    }
308→
309→    camera_model_t camera_model = CAMERA_NONE;
310→    err = camera_probe(config, &camera_model);
311→    if (err != ESP_OK) {
312→        ESP_LOGE(TAG, "Camera probe failed with error 0x%x(%s)", err, esp_err_to_name(err));
313→        goto fail;
314→    }
315→
316→    framesize_t frame_size = (framesize_t) config->frame_size;
317→    pixformat_t pix_format = (pixformat_t) config->pixel_format;
318→
319→    if (PIXFORMAT_JPEG == pix_format && (!camera_sensor[camera_model].support_jpeg)) {
320→        ESP_LOGE(TAG, "JPEG format is not supported on this sensor");
321→        err = ESP_ERR_NOT_SUPPORTED;
322→        goto fail;
323→    }
324→
325→    if (frame_size > camera_sensor[camera_model].max_size) {
326→        ESP_LOGW(TAG, "The frame size exceeds the maximum for this sensor, it will be forced to the maximum possible value");
327→        frame_size = camera_sensor[camera_model].max_size;
328→    }
329→
330→    err = cam_config(config, frame_size, s_state->sensor.id.PID);
331→    if (err != ESP_OK) {
332→        ESP_LOGE(TAG, "Camera config failed with error 0x%x", err);
333→        goto fail;
334→    }
335→
336→    s_state->sensor.status.framesize = frame_size;
337→    s_state->sensor.pixformat = pix_format;
338→
339→    ESP_LOGD(TAG, "Setting frame size to %dx%d", resolution[frame_size].width, resolution[frame_size].height);
340→    if (s_state->sensor.set_framesize(&s_state->sensor, frame_size) != 0) {
341→        ESP_LOGE(TAG, "Failed to set frame size");
342→        err = ESP_ERR_CAMERA_FAILED_TO_SET_FRAME_SIZE;
343→        goto fail;
344→    }
345→    s_state->sensor.set_pixformat(&s_state->sensor, pix_format);
346→#if CONFIG_CAMERA_CONVERTER_ENABLED
347→    if(config->conv_mode) {
348→        s_state->sensor.pixformat = get_output_data_format(config->conv_mode); // If conversion enabled, change the out data format by conversion mode
349→    }
350→#endif
351→
352→    if (s_state->sensor.id.PID == OV2640_PID) {
353→        s_state->sensor.set_gainceiling(&s_state->sensor, GAINCEILING_2X);
354→        s_state->sensor.set_bpc(&s_state->sensor, false);
355→        s_state->sensor.set_wpc(&s_state->sensor, true);
356→        s_state->sensor.set_lenc(&s_state->sensor, true);
357→    }
358→
359→    if (pix_format == PIXFORMAT_JPEG) {
360→        s_state->sensor.set_quality(&s_state->sensor, config->jpeg_quality);
361→    }
362→    s_state->sensor.init_status(&s_state->sensor);
363→
364→    cam_start();
365→
366→    return ESP_OK;
367→
368→fail:
369→    esp_camera_deinit();
370→    return err;
371→}
