 47→static int sccb_i2c_port;
 48→static bool sccb_owns_i2c_port;
 49→
 50→int SCCB_Init(int pin_sda, int pin_scl)
 51→{
 52→    ESP_LOGI(TAG, "pin_sda %d pin_scl %d", pin_sda, pin_scl);
 53→    i2c_config_t conf;
 54→    esp_err_t ret;
 55→
 56→    memset(&conf, 0, sizeof(i2c_config_t));
 57→
 58→    sccb_i2c_port = SCCB_I2C_PORT_DEFAULT;
 59→    sccb_owns_i2c_port = true;
 60→    ESP_LOGI(TAG, "sccb_i2c_port=%d", sccb_i2c_port);
 61→
 62→    conf.mode = I2C_MODE_MASTER;
 63→    conf.sda_io_num = pin_sda;
 64→    conf.sda_pullup_en = GPIO_PULLUP_ENABLE;
 65→    conf.scl_io_num = pin_scl;
 66→    conf.scl_pullup_en = GPIO_PULLUP_ENABLE;
 67→    conf.master.clk_speed = SCCB_FREQ;
 68→
 69→    if ((ret =  i2c_param_config(sccb_i2c_port, &conf)) != ESP_OK) {
 70→        return ret;
 71→    }
 72→
 73→    return i2c_driver_install(sccb_i2c_port, conf.mode, 0, 0, 0);
 74→}
 75→
 76→int SCCB_Use_Port(int i2c_num) { // sccb use an already initialized I2C port
 77→    if (sccb_owns_i2c_port) {
 78→        SCCB_Deinit();
 79→    }
 80→    if (i2c_num < 0 || i2c_num > I2C_NUM_MAX) {
 81→        return ESP_ERR_INVALID_ARG;
 82→    }
 83→    sccb_i2c_port = i2c_num;
 84→    sccb_owns_i2c_port = false; // in this case, camera doesn't own the i2c port
 85→    return ESP_OK;
 86→}
 87→
 88→int SCCB_Deinit(void)
 89→{
 90→    if (!sccb_owns_i2c_port) {
 91→        return ESP_OK;
 92→    }
 93→    sccb_owns_i2c_port = false;
 94→    return i2c_driver_delete(sccb_i2c_port);
 95→}
