#define MAC_IP      "192.168.1.7"
#define LOG_PORT    5555

/* ─── Camera pins (AI-Thinker ESP32-CAM) ──────────────────── */
#define CAM_PWDN   32
#define CAM_RESET  (-1)
#define CAM_XCLK   0
#define CAM_SIOD   26
#define CAM_SIOC   27
#define CAM_D7     35
