168→static void qr_task(void *arg)
169→{
170→    struct quirc *qr = quirc_new();
171→    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
172→        ESP_LOGE(TAG, "quirc init failed");
173→        vTaskDelete(NULL);
174→        return;
175→    }
176→
177→    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
178→    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
179→    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
180→    if (!rgb || !code || !data) {
181→        ESP_LOGE(TAG, "PSRAM alloc failed for QR");
182→        vTaskDelete(NULL);
183→        return;
184→    }
185→    ESP_LOGI(TAG, "QR scanner ready");
186→
187→    while (1) {
188→        vTaskDelay(pdMS_TO_TICKS(500));
189→
190→        camera_fb_t *fb = esp_camera_fb_get();
191→        if (!fb) { ESP_LOGW(TAG, "QR: fb_get failed"); continue; }
192→
193→        bool ok = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
194→        esp_camera_fb_return(fb);
195→        if (!ok) { ESP_LOGW(TAG, "QR: jpg decode failed"); continue; }
196→
197→        int w, h;
198→        uint8_t *qbuf = quirc_begin(qr, &w, &h);
199→        for (int i = 0; i < w * h; i++) {
200→            int ri = i * 3;
201→            qbuf[i] = (uint8_t)((rgb[ri]*77 + rgb[ri+1]*150 + rgb[ri+2]*29) >> 8);
202→        }
203→        quirc_end(qr);
204→
205→        bool found = false;
206→        int n = quirc_count(qr);
207→        ESP_LOGI(TAG, "QR: quirc found %d candidates", n);
208→        for (int i = 0; i < n; i++) {
209→            quirc_extract(qr, i, code);
210→            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
211→                xSemaphoreTake(s_qr_lock, portMAX_DELAY);
212→                int plen = data->payload_len;
213→                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
214→                memcpy(s_qr_text, data->payload, plen);
215→                s_qr_text[plen] = '\0';
216→                s_qr_found = true;
217→                for (int j = 0; j < 4; j++) {
218→                    s_qr_corners[j*2]   = code->corners[j].x;
219→                    s_qr_corners[j*2+1] = code->corners[j].y;
220→                }
221→                xSemaphoreGive(s_qr_lock);
222→                found = true;
223→                ESP_LOGI(TAG, "QR DECODED: %.128s", s_qr_text);
224→                break;
225→            }
226→        }
