#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdarg.h>
#include "esp_heap_caps.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "freertos/semphr.h"
#include "freertos/event_groups.h"
#include "esp_log.h"
#include "esp_wifi.h"
#include "esp_event.h"
#include "esp_netif.h"
#include "esp_http_server.h"
#include "esp_camera.h"
#include "img_converters.h"
#include "nvs_flash.h"
#include "quirc.h"
#include "lwip/sockets.h"

static const char *TAG = "QR_SCAN";

/* ─── WiFi STA ────────────────────────────────────────────── */
#define WIFI_SSID   "MGTS_145"
#define WIFI_PASS   "Romacapitale"
#define MAC_IP      "192.168.1.7"
#define LOG_PORT    5555

/* ─── Camera pins (AI-Thinker ESP32-CAM) ──────────────────── */
#define CAM_PWDN   32
#define CAM_RESET  (-1)
#define CAM_XCLK   0
#define CAM_SIOD   26
#define CAM_SIOC   27
#define CAM_D7     35
#define CAM_D6     34
#define CAM_D5     39
#define CAM_D4     36
#define CAM_D3     21
#define CAM_D2     19
#define CAM_D1     18
#define CAM_D0     5
#define CAM_VSYNC  25
#define CAM_HREF   23
#define CAM_PCLK   22

#define FRAME_W    320
#define FRAME_H    240

/* ─── UDP logging ─────────────────────────────────────────── */
static int s_log_sock = -1;
static struct sockaddr_in s_log_dest;

static int udp_log_vprintf(const char *fmt, va_list args)
{
    char buf[512];
    int len = vsnprintf(buf, sizeof(buf), fmt, args);
    if (s_log_sock >= 0 && len > 0) {
        sendto(s_log_sock, buf, len, 0,
               (struct sockaddr *)&s_log_dest, sizeof(s_log_dest));
    }
    return vprintf(fmt, args);
}

static void udp_log_init(void)
{
    s_log_sock = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (s_log_sock < 0) return;
    memset(&s_log_dest, 0, sizeof(s_log_dest));
    s_log_dest.sin_family = AF_INET;
    s_log_dest.sin_port = htons(LOG_PORT);
    inet_aton(MAC_IP, &s_log_dest.sin_addr);
    esp_log_set_vprintf(udp_log_vprintf);
}

/* ─── QR result ───────────────────────────────────────────── */
static SemaphoreHandle_t s_qr_lock;
static char  s_qr_text[1024] = "";
static bool  s_qr_found = false;
static int   s_qr_corners[8] = {0};

/* ─── WiFi STA ────────────────────────────────────────────── */
static EventGroupHandle_t s_wifi_eg;
#define WIFI_CONNECTED BIT0

static void wifi_handler(void *arg, esp_event_base_t base,
                         int32_t id, void *data)
{
    if (base == WIFI_EVENT && id == WIFI_EVENT_STA_START) {
        esp_wifi_connect();
    } else if (base == WIFI_EVENT && id == WIFI_EVENT_STA_DISCONNECTED) {
        wifi_event_sta_disconnected_t *d = (wifi_event_sta_disconnected_t *)data;
        ESP_LOGW(TAG, "WiFi disconnected, reason=%d, reconnecting...", d->reason);
        esp_wifi_connect();
    } else if (base == IP_EVENT && id == IP_EVENT_STA_GOT_IP) {
        ip_event_got_ip_t *e = (ip_event_got_ip_t *)data;
        ESP_LOGI(TAG, "Got IP: " IPSTR, IP2STR(&e->ip_info.ip));
        xEventGroupSetBits(s_wifi_eg, WIFI_CONNECTED);
    }
}

static esp_err_t wifi_init_sta(void)
{
    s_wifi_eg = xEventGroupCreate();
    ESP_ERROR_CHECK(esp_netif_init());
    ESP_ERROR_CHECK(esp_event_loop_create_default());
    esp_netif_create_default_wifi_sta();

    wifi_init_config_t wcfg = WIFI_INIT_CONFIG_DEFAULT();
    ESP_ERROR_CHECK(esp_wifi_init(&wcfg));

    ESP_ERROR_CHECK(esp_event_handler_instance_register(
        WIFI_EVENT, ESP_EVENT_ANY_ID, &wifi_handler, NULL, NULL));
    ESP_ERROR_CHECK(esp_event_handler_instance_register(
        IP_EVENT, IP_EVENT_STA_GOT_IP, &wifi_handler, NULL, NULL));

    wifi_config_t sta = {
        .sta = {
            .ssid     = WIFI_SSID,
            .password = WIFI_PASS,
        },
    };
    ESP_ERROR_CHECK(esp_wifi_set_mode(WIFI_MODE_STA));
    ESP_ERROR_CHECK(esp_wifi_set_config(WIFI_IF_STA, &sta));
    ESP_ERROR_CHECK(esp_wifi_start());

    ESP_LOGI(TAG, "Connecting to WiFi \"%s\"...", WIFI_SSID);

    EventBits_t bits = xEventGroupWaitBits(
        s_wifi_eg, WIFI_CONNECTED, pdFALSE, pdFALSE, pdMS_TO_TICKS(15000));

    if (bits & WIFI_CONNECTED) {
        ESP_LOGI(TAG, "WiFi connected!");
        return ESP_OK;
    }
    ESP_LOGE(TAG, "WiFi connect timeout");
    return ESP_FAIL;
}

/* ─── Camera init ─────────────────────────────────────────── */
static esp_err_t camera_init(void)
{
    camera_config_t cfg = {
        .pin_pwdn     = CAM_PWDN,   .pin_reset   = CAM_RESET,
        .pin_xclk     = CAM_XCLK,
        .pin_sccb_sda = CAM_SIOD,   .pin_sccb_scl = CAM_SIOC,
        .pin_d7 = CAM_D7, .pin_d6 = CAM_D6, .pin_d5 = CAM_D5, .pin_d4 = CAM_D4,
        .pin_d3 = CAM_D3, .pin_d2 = CAM_D2, .pin_d1 = CAM_D1, .pin_d0 = CAM_D0,
        .pin_vsync    = CAM_VSYNC,
        .pin_href     = CAM_HREF,
        .pin_pclk     = CAM_PCLK,
        .xclk_freq_hz = 20000000,
        .ledc_timer   = LEDC_TIMER_0,
        .ledc_channel = LEDC_CHANNEL_0,
        .pixel_format = PIXFORMAT_JPEG,
        .frame_size   = FRAMESIZE_QVGA,
        .jpeg_quality = 12,
        .fb_count     = 2,
        .fb_location  = CAMERA_FB_IN_PSRAM,
        .grab_mode    = CAMERA_GRAB_WHEN_EMPTY,
    };
    esp_err_t err = esp_camera_init(&cfg);
    if (err != ESP_OK) ESP_LOGE(TAG, "Camera init failed: 0x%x", err);
    return err;
}

/* ─── QR scan task ────────────────────────────────────────── */
static void qr_task(void *arg)
{
    struct quirc *qr = quirc_new();
    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
        ESP_LOGE(TAG, "quirc init failed");
        vTaskDelete(NULL);
        return;
    }

    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
    if (!rgb || !code || !data) {
        ESP_LOGE(TAG, "PSRAM alloc failed for QR");
        vTaskDelete(NULL);
        return;
    }
    ESP_LOGI(TAG, "QR scanner ready");

    while (1) {
        vTaskDelay(pdMS_TO_TICKS(500));

        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) { ESP_LOGW(TAG, "QR: fb_get failed"); continue; }

        bool ok = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
        esp_camera_fb_return(fb);
        if (!ok) { ESP_LOGW(TAG, "QR: jpg decode failed"); continue; }

        int w, h;
        uint8_t *qbuf = quirc_begin(qr, &w, &h);
        for (int i = 0; i < w * h; i++) {
            int ri = i * 3;
            qbuf[i] = (uint8_t)((rgb[ri]*77 + rgb[ri+1]*150 + rgb[ri+2]*29) >> 8);
        }
        quirc_end(qr);

        bool found = false;
        int n = quirc_count(qr);
        ESP_LOGI(TAG, "QR: quirc found %d candidates", n);
        for (int i = 0; i < n; i++) {
            quirc_extract(qr, i, code);
            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
                xSemaphoreTake(s_qr_lock, portMAX_DELAY);
                int plen = data->payload_len;
                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
                memcpy(s_qr_text, data->payload, plen);
                s_qr_text[plen] = '\0';
                s_qr_found = true;
                for (int j = 0; j < 4; j++) {
                    s_qr_corners[j*2]   = code->corners[j].x;
                    s_qr_corners[j*2+1] = code->corners[j].y;
                }
                xSemaphoreGive(s_qr_lock);
                found = true;
                ESP_LOGI(TAG, "QR DECODED: %.128s", s_qr_text);
                break;
            }
        }
        if (!found) {
            xSemaphoreTake(s_qr_lock, portMAX_DELAY);
            s_qr_found = false;
            xSemaphoreGive(s_qr_lock);
        }
    }
}

/* ─── HTTP: index ─────────────────────────────────────────── */
static const char INDEX_HTML[] =
"<!DOCTYPE html><html><head>"
"<meta charset=\"utf-8\">"
"<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">"
"<title>ESP32 QR Scanner</title>"
"<style>"
"*{margin:0;padding:0;box-sizing:border-box}"
"body{background:#0f0f1a;color:#e0e0e0;font-family:'Courier New',monospace;"
"display:flex;flex-direction:column;align-items:center;padding:20px}"
"h1{color:#e94560;margin-bottom:16px;font-size:1.5em}"
".wrap{position:relative;display:inline-block}"
"#cam{border:2px solid #e94560;border-radius:8px;width:640px;height:480px;"
"object-fit:contain;background:#000;display:block}"
"#ov{position:absolute;top:2px;left:2px;pointer-events:none}"
"#qr{background:#16213e;padding:14px 20px;margin-top:14px;border-radius:8px;"
"width:640px;min-height:48px;font-size:1.1em;word-break:break-all}"
".found{color:#0f0}.no{color:#555}"
"</style></head><body>"
"<h1>ESP32-CAM QR Scanner</h1>"
"<div class=\"wrap\">"
"<img id=\"cam\"/>"
"<canvas id=\"ov\" width=\"636\" height=\"476\"></canvas>"
"</div>"
"<div id=\"qr\"><span class=\"no\">scanning...</span></div>"
"<script>\n"
"document.getElementById('cam').src='/stream';\n"
"const cv=document.getElementById('ov');\n"
"const ctx=cv.getContext('2d');\n"
"const sx=636/320,sy=476/240;\n"
"setInterval(()=>{\n"
"fetch('/qr').then(r=>r.json()).then(d=>{\n"
"  ctx.clearRect(0,0,636,476);\n"
"  const el=document.getElementById('qr');\n"
"  if(d.found){\n"
"    el.innerHTML='<span class=\"found\">'+d.data.replace(/&/g,'&amp;')"
".replace(/</g,'&lt;').replace(/>/g,'&gt;')+'</span>';\n"
"    if(d.c){\n"
"      ctx.strokeStyle='#0f0';ctx.lineWidth=3;ctx.beginPath();\n"
"      ctx.moveTo(d.c[0]*sx,d.c[1]*sy);\n"
"      ctx.lineTo(d.c[2]*sx,d.c[3]*sy);\n"
"      ctx.lineTo(d.c[4]*sx,d.c[5]*sy);\n"
"      ctx.lineTo(d.c[6]*sx,d.c[7]*sy);\n"
"      ctx.closePath();ctx.stroke();\n"
"    }\n"
"  }else{\n"
"    el.innerHTML='<span class=\"no\">scanning...</span>';\n"
"  }\n"
"}).catch(()=>{});\n"
"},500);\n"
"</script></body></html>";

static esp_err_t index_handler(httpd_req_t *req)
{
    httpd_resp_set_type(req, "text/html");
    return httpd_resp_send(req, INDEX_HTML, sizeof(INDEX_HTML) - 1);
}

/* ─── HTTP: QR JSON ───────────────────────────────────────── */
static esp_err_t qr_handler(httpd_req_t *req)
{
    char buf[1300];
    xSemaphoreTake(s_qr_lock, portMAX_DELAY);
    if (s_qr_found) {
        char esc[1024]; int j = 0;
        for (int i = 0; s_qr_text[i] && j < (int)sizeof(esc)-6; i++) {
            char c = s_qr_text[i];
            if (c=='"'||c=='\\') esc[j++]='\\';
            else if (c=='\n'){esc[j++]='\\';c='n';}
            else if (c=='\r'){esc[j++]='\\';c='r';}
            esc[j++]=c;
        }
        esc[j]='\0';
        snprintf(buf, sizeof(buf),
            "{\"found\":true,\"data\":\"%s\","
            "\"c\":[%d,%d,%d,%d,%d,%d,%d,%d]}", esc,
            s_qr_corners[0],s_qr_corners[1],s_qr_corners[2],s_qr_corners[3],
            s_qr_corners[4],s_qr_corners[5],s_qr_corners[6],s_qr_corners[7]);
    } else {
        strcpy(buf, "{\"found\":false,\"data\":\"\"}");
    }
    xSemaphoreGive(s_qr_lock);
    httpd_resp_set_type(req, "application/json");
    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
    return httpd_resp_send(req, buf, strlen(buf));
}

/* ─── HTTP: MJPEG stream (direct capture) ─────────────────── */
#define BOUNDARY "frame"

static esp_err_t stream_handler(httpd_req_t *req)
{
    esp_err_t res;
    char hdr[80];

    res = httpd_resp_set_type(req, "multipart/x-mixed-replace;boundary=" BOUNDARY);
    if (res != ESP_OK) return res;

    ESP_LOGI(TAG, "Stream client connected");

    while (true) {
        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) {
            ESP_LOGE(TAG, "stream: fb_get fail");
            vTaskDelay(pdMS_TO_TICKS(100));
            continue;
        }

        int hlen = snprintf(hdr, sizeof(hdr),
            "--" BOUNDARY "\r\n"
            "Content-Type: image/jpeg\r\n"
            "Content-Length: %u\r\n\r\n", (unsigned)fb->len);

        res = httpd_resp_send_chunk(req, hdr, hlen);
        if (res == ESP_OK)
            res = httpd_resp_send_chunk(req, (const char *)fb->buf, fb->len);
        if (res == ESP_OK)
            res = httpd_resp_send_chunk(req, "\r\n", 2);

        esp_camera_fb_return(fb);

        if (res != ESP_OK) {
            ESP_LOGI(TAG, "Stream client disconnected");
            break;
        }
        vTaskDelay(pdMS_TO_TICKS(30));
    }
    return res;
}

/* ─── Web server ──────────────────────────────────────────── */
static void start_webserver(void)
{
    httpd_config_t cfg = HTTPD_DEFAULT_CONFIG();
    cfg.server_port = 80;
    cfg.lru_purge_enable = true;
    cfg.max_uri_handlers = 4;
    cfg.stack_size = 16384;
    httpd_handle_t srv = NULL;
    ESP_ERROR_CHECK(httpd_start(&srv, &cfg));

    httpd_uri_t u1 = {.uri="/",      .method=HTTP_GET, .handler=index_handler};
    httpd_uri_t u2 = {.uri="/qr",    .method=HTTP_GET, .handler=qr_handler};
    httpd_uri_t u3 = {.uri="/stream", .method=HTTP_GET, .handler=stream_handler};
    httpd_register_uri_handler(srv, &u1);
    httpd_register_uri_handler(srv, &u2);
    httpd_register_uri_handler(srv, &u3);
    ESP_LOGI(TAG, "HTTP server on port 80");
}

/* ─── LED blink task (GPIO4 flash LED) ────────────────────── */
#define LED_GPIO 4

static void led_blink_task(void *arg)
{
    gpio_config_t io = { .pin_bit_mask = 1ULL << LED_GPIO,
                         .mode = GPIO_MODE_OUTPUT };
    gpio_config(&io);
    while (1) {
        gpio_set_level(LED_GPIO, 1);
        vTaskDelay(pdMS_TO_TICKS(200));
        gpio_set_level(LED_GPIO, 0);
        vTaskDelay(pdMS_TO_TICKS(800));
    }
}

/* ─── app_main ────────────────────────────────────────────── */
void app_main(void)
{
    ESP_LOGI(TAG, "=== ESP32-CAM QR Scanner ===");

    /* Blink LED immediately to show ESP32 is alive */
    xTaskCreate(led_blink_task, "led", 2048, NULL, 1, NULL);

    esp_err_t ret = nvs_flash_init();
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES ||
        ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    s_qr_lock = xSemaphoreCreateMutex();

    /* WiFi FIRST — so we can get UDP logs even if camera fails */
    if (wifi_init_sta() != ESP_OK) {
        ESP_LOGE(TAG, "WiFi FAIL — continuing anyway for serial diag");
    }

    /* UDP logging → Mac */
    udp_log_init();
    ESP_LOGI(TAG, "UDP logging to %s:%d", MAC_IP, LOG_PORT);

    /* Camera */
    if (camera_init() != ESP_OK) {
        ESP_LOGE(TAG, "Camera FAIL — check I2C scan above for sensor info");
        ESP_LOGE(TAG, "Halting here (no restart) so you can read the log");
        while (1) vTaskDelay(pdMS_TO_TICKS(10000));
    }
    ESP_LOGI(TAG, "Camera OK (PSRAM free: %lu)",
             (unsigned long)heap_caps_get_free_size(MALLOC_CAP_SPIRAM));

    /* Web server */
    start_webserver();

    /* QR task */
    xTaskCreatePinnedToCore(qr_task, "qr", 64 * 1024, NULL, 3, NULL, 0);

    ESP_LOGI(TAG, "All systems GO");
}

