/* ─── QR scan task ────────────────────────────────────────── */
static void qr_task(void *arg)
{
    ESP_LOGI(TAG, "QR task started on core %d", xPortGetCoreID());
    vTaskDelay(pdMS_TO_TICKS(1000));  /* let system settle */

    ESP_LOGI(TAG, "QR: quirc_new...");
    struct quirc *qr = quirc_new();
    if (!qr) {
        ESP_LOGE(TAG, "QR: quirc_new FAILED");
        vTaskDelete(NULL);
        return;
    }
    ESP_LOGI(TAG, "QR: quirc_resize(%d,%d)...", FRAME_W, FRAME_H);
    if (quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
        ESP_LOGE(TAG, "QR: quirc_resize FAILED");
        vTaskDelete(NULL);
        return;
    }

    ESP_LOGI(TAG, "QR: allocating RGB buffer (%d bytes from PSRAM)...", FRAME_W * FRAME_H * 3);
    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
    ESP_LOGI(TAG, "QR: allocating quirc_code (%d bytes)...", (int)sizeof(struct quirc_code));
    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
    ESP_LOGI(TAG, "QR: allocating quirc_data (%d bytes)...", (int)sizeof(struct quirc_data));
    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
    if (!rgb || !code || !data) {
        ESP_LOGE(TAG, "PSRAM alloc failed: rgb=%p code=%p data=%p", rgb, code, data);
        vTaskDelete(NULL);
        return;
    }
    ESP_LOGI(TAG, "QR scanner ready (rgb=%p code=%p data=%p)", rgb, code, data);

    while (1) {
        vTaskDelay(pdMS_TO_TICKS(500));

        camera_fb_t *fb = esp_camera_fb_get();
        if (!fb) { ESP_LOGW(TAG, "QR: fb_get failed"); continue; }

        unsigned fb_len = fb->len;
        ESP_LOGI(TAG, "QR: fb len=%u fmt=%d %dx%d", fb_len, fb->format, fb->width, fb->height);

        bool ok = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
        esp_camera_fb_return(fb);
        if (!ok) { ESP_LOGW(TAG, "QR: jpg decode failed"); continue; }

        int w, h;
        uint8_t *qbuf = quirc_begin(qr, &w, &h);
        for (int i = 0; i < w * h; i++) {
            int ri = i * 3;
            qbuf[i] = (uint8_t)((rgb[ri]*77 + rgb[ri+1]*150 + rgb[ri+2]*29) >> 8);
        }
        quirc_end(qr);

        bool found = false;
        int n = quirc_count(qr);
        ESP_LOGI(TAG, "QR: fb=%u bytes, quirc candidates=%d", fb_len, n);
        for (int i = 0; i < n; i++) {
            quirc_extract(qr, i, code);
            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
                xSemaphoreTake(s_qr_lock, portMAX_DELAY);
                int plen = data->payload_len;
                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
                memcpy(s_qr_text, data->payload, plen);
                s_qr_text[plen] = '\0';
                s_qr_found = true;
                for (int j = 0; j < 4; j++) {
                    s_qr_corners[j*2]   = code->corners[j].x;
                    s_qr_corners[j*2+1] = code->corners[j].y;
                }
                xSemaphoreGive(s_qr_lock);
                found = true;
                ESP_LOGI(TAG, ">>> QR DECODED: %.128s", s_qr_text);
                break;
            }
        }
        if (!found) {
            xSemaphoreTake(s_qr_lock, portMAX_DELAY);
            s_qr_found = false;
            xSemaphoreGive(s_qr_lock);
        }
    }
}

