    if (quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
        ESP_LOGE(TAG, "QR: quirc_resize FAILED");
        vTaskDelete(NULL);
        return;
    }

    ESP_LOGI(TAG, "QR: allocating RGB buffer (%d bytes from PSRAM)...", FRAME_W * FRAME_H * 3);
    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
