105→        .jpeg_quality = 6,                 /* lower = better quality */
106→        .fb_count     = 2,
107→        .fb_location  = CAMERA_FB_IN_PSRAM,
108→        .grab_mode    = CAMERA_GRAB_LATEST, /* always freshest frame */
109→    };
110→
111→    esp_err_t err = esp_camera_init(&cfg);
112→    if (err != ESP_OK) {
113→        ESP_LOGE(TAG, "Camera init FAILED: 0x%x (%s)", err, esp_err_to_name(err));
114→    } else {
115→        sensor_t *s = esp_camera_sensor_get();
116→        if (s) {
117→            ESP_LOGI(TAG, "Camera sensor PID=0x%02X VER=0x%02X",
118→                     s->id.PID, s->id.VER);
119→            /* Improve image quality for QR detection */
120→            s->set_quality(s, 6);
121→            s->set_contrast(s, 1);       /* +1 contrast */
122→            s->set_sharpness(s, 1);      /* +1 sharpness */
123→            s->set_denoise(s, 1);        /* denoise on */
124→        }
125→        ESP_LOGI(TAG, "Camera init OK");
126→    }
127→    ESP_LOGI(TAG, "  Free heap after: %lu  Free PSRAM after: %lu",
128→             (unsigned long)esp_get_free_heap_size(),
129→             (unsigned long)heap_caps_get_free_size(MALLOC_CAP_SPIRAM));
130→    return err;
131→}
