133→/* ─── QR scan task ────────────────────────────────────────── */
134→static void qr_task(void *arg)
135→{
136→    ESP_LOGI(TAG, "QR task started on core %d", xPortGetCoreID());
137→    vTaskDelay(pdMS_TO_TICKS(1000));
138→
139→    struct quirc *qr = quirc_new();
140→    if (!qr || quirc_resize(qr, FRAME_W, FRAME_H) < 0) {
141→        ESP_LOGE(TAG, "quirc init FAILED");
142→        vTaskDelete(NULL);
143→        return;
144→    }
145→
146→    uint8_t *rgb  = heap_caps_malloc(FRAME_W * FRAME_H * 3, MALLOC_CAP_SPIRAM);
147→    struct quirc_code *code = heap_caps_malloc(sizeof(struct quirc_code), MALLOC_CAP_SPIRAM);
148→    struct quirc_data *data = heap_caps_malloc(sizeof(struct quirc_data), MALLOC_CAP_SPIRAM);
149→    if (!rgb || !code || !data) {
150→        ESP_LOGE(TAG, "PSRAM alloc FAILED");
151→        vTaskDelete(NULL);
152→        return;
153→    }
154→    ESP_LOGI(TAG, "QR scanner ready (%dx%d)", FRAME_W, FRAME_H);
155→
156→    while (1) {
157→        vTaskDelay(pdMS_TO_TICKS(300));
158→
159→        camera_fb_t *fb = esp_camera_fb_get();
160→        if (!fb) continue;
161→
162→        bool ok = fmt2rgb888(fb->buf, fb->len, PIXFORMAT_JPEG, rgb);
163→        esp_camera_fb_return(fb);
164→        if (!ok) continue;
165→
166→        int w, h;
167→        uint8_t *qbuf = quirc_begin(qr, &w, &h);
168→        for (int i = 0; i < w * h; i++) {
169→            int ri = i * 3;
170→            qbuf[i] = (uint8_t)((rgb[ri]*77 + rgb[ri+1]*150 + rgb[ri+2]*29) >> 8);
171→        }
172→        quirc_end(qr);
173→
174→        bool found = false;
175→        int n = quirc_count(qr);
176→        for (int i = 0; i < n; i++) {
177→            quirc_extract(qr, i, code);
178→            if (quirc_decode(code, data) == QUIRC_SUCCESS) {
179→                xSemaphoreTake(s_qr_lock, portMAX_DELAY);
180→                int plen = data->payload_len;
181→                if (plen > (int)sizeof(s_qr_text) - 1) plen = sizeof(s_qr_text) - 1;
182→                memcpy(s_qr_text, data->payload, plen);
183→                s_qr_text[plen] = '\0';
184→                s_qr_found = true;
185→                s_qr_found_time = esp_timer_get_time() / 1000; /* ms */
186→                for (int j = 0; j < 4; j++) {
187→                    s_qr_corners[j*2]   = code->corners[j].x;
188→                    s_qr_corners[j*2+1] = code->corners[j].y;
189→                }
190→                xSemaphoreGive(s_qr_lock);
191→                found = true;
192→                ESP_LOGI(TAG, ">>> QR DECODED: %.128s", s_qr_text);
193→                ESP_LOGI(TAG, "    corners: (%d,%d) (%d,%d) (%d,%d) (%d,%d)",
194→                    s_qr_corners[0],s_qr_corners[1],s_qr_corners[2],s_qr_corners[3],
195→                    s_qr_corners[4],s_qr_corners[5],s_qr_corners[6],s_qr_corners[7]);
196→                break;
197→            }
198→        }
199→        if (!found) {
200→            /* Only clear after QR_HOLD_MS so JS can pick it up */
201→            int64_t now = esp_timer_get_time() / 1000;
202→            if (s_qr_found && (now - s_qr_found_time > QR_HOLD_MS)) {
203→                xSemaphoreTake(s_qr_lock, portMAX_DELAY);
204→                s_qr_found = false;
205→                xSemaphoreGive(s_qr_lock);
206→            }
207→        }
208→    }
209→}
