269→/* ─── HTTP: QR JSON ───────────────────────────────────────── */
270→static esp_err_t qr_handler(httpd_req_t *req)
271→{
272→    char buf[1300];
273→    xSemaphoreTake(s_qr_lock, portMAX_DELAY);
274→    if (s_qr_found) {
275→        char esc[1024]; int j = 0;
276→        for (int i = 0; s_qr_text[i] && j < (int)sizeof(esc)-6; i++) {
277→            char c = s_qr_text[i];
278→            if (c=='"'||c=='\\') esc[j++]='\\';
279→            else if (c=='\n'){esc[j++]='\\';c='n';}
280→            else if (c=='\r'){esc[j++]='\\';c='r';}
281→            esc[j++]=c;
282→        }
283→        esc[j]='\0';
284→        snprintf(buf, sizeof(buf),
285→            "{\"found\":true,\"data\":\"%s\","
286→            "\"c\":[%d,%d,%d,%d,%d,%d,%d,%d]}", esc,
287→            s_qr_corners[0],s_qr_corners[1],s_qr_corners[2],s_qr_corners[3],
288→            s_qr_corners[4],s_qr_corners[5],s_qr_corners[6],s_qr_corners[7]);
289→    } else {
290→        strcpy(buf, "{\"found\":false,\"data\":\"\"}");
291→    }
292→    xSemaphoreGive(s_qr_lock);
293→    httpd_resp_set_type(req, "application/json");
294→    httpd_resp_set_hdr(req, "Access-Control-Allow-Origin", "*");
295→    return httpd_resp_send(req, buf, strlen(buf));
296→}
