298→/* ─── HTTP: MJPEG stream ──────────────────────────────────── */
299→#define BOUNDARY "frame"
300→
301→static esp_err_t stream_handler(httpd_req_t *req)
302→{
303→    esp_err_t res;
304→    char hdr[80];
305→
306→    res = httpd_resp_set_type(req, "multipart/x-mixed-replace;boundary=" BOUNDARY);
307→    if (res != ESP_OK) return res;
308→
309→    ESP_LOGI(TAG, "Stream client connected");
310→
311→    while (true) {
312→        camera_fb_t *fb = esp_camera_fb_get();
313→        if (!fb) {
314→            ESP_LOGE(TAG, "stream: fb_get fail");
315→            vTaskDelay(pdMS_TO_TICKS(100));
316→            continue;
317→        }
318→
319→        int hlen = snprintf(hdr, sizeof(hdr),
320→            "--" BOUNDARY "\r\n"
321→            "Content-Type: image/jpeg\r\n"
322→            "Content-Length: %u\r\n\r\n", (unsigned)fb->len);
323→
324→        res = httpd_resp_send_chunk(req, hdr, hlen);
325→        if (res == ESP_OK)
326→            res = httpd_resp_send_chunk(req, (const char *)fb->buf, fb->len);
327→        if (res == ESP_OK)
328→            res = httpd_resp_send_chunk(req, "\r\n", 2);
329→
330→        esp_camera_fb_return(fb);
331→
332→        if (res != ESP_OK) {
333→            ESP_LOGI(TAG, "Stream client disconnected");
334→            break;
335→        }
336→        vTaskDelay(pdMS_TO_TICKS(30));
337→    }
338→    return res;
339→}
